import React, { useState, useRef, useEffect } from "react";
import ReactMarkdown from "react-markdown";

const OWNER_NAME = "Abdy Mohameden";
const SYSTEM_PROMPT = `Tu es un assistant IA personnel et dévoué, créé exclusivement pour ${OWNER_NAME}.
Tu t'adresses toujours directement à ${OWNER_NAME} par son prénom.
Tu réponds en français par défaut, mais tu peux aussi répondre en arabe ou en anglais si ${OWNER_NAME} le souhaite.
Tu es intelligent, chaleureux, précis et toujours disponible pour aider ${OWNER_NAME}.
Tu te souviens qu'il habite à Nouakchott, Mauritanie, et tu adaptes tes réponses à son contexte.
Commence toujours ta première réponse par "Bonjour Abdy ! 👋" pour le saluer.`;

const API_URL = "https://openrouter.ai/api/v1/chat/completions";


const FREE_MODEL = "google/gemini-2.0-flash-001";

function formatTime(date) {
  return date.toLocaleTimeString("fr-FR", { hour: "2-digit", minute: "2-digit" });
}

function TypingDots() {
  return (
    <div className="flex items-center gap-1 px-4 py-3">
      {[0, 1, 2].map((i) => (
        <span key={i} className="w-2 h-2 rounded-full bg-violet-400 animate-pulse2" style={{ animationDelay: `${i * 0.2}s` }} />
      ))}
    </div>
  );
}

function Message({ msg }) {
  const isUser = msg.role === "user";
  return (
    <div className={`flex gap-3 animate-slide-up ${isUser ? "flex-row-reverse" : "flex-row"} mb-4`}>
      <div className={`flex-shrink-0 w-9 h-9 rounded-xl flex items-center justify-center text-sm font-bold ${isUser ? "bg-violet-600 text-white" : "bg-gradient-to-br from-indigo-500 to-purple-600 text-white"}`}>
        {isUser ? "A" : "🤖"}
      </div>
      <div className={`max-w-[75%] ${isUser ? "items-end" : "items-start"} flex flex-col gap-1`}>
        <div className={`px-4 py-3 rounded-2xl text-sm leading-relaxed ${isUser ? "bg-violet-600 text-white rounded-tr-sm" : "bg-[#1a1a2e] border border-white/10 text-gray-200 rounded-tl-sm"}`}>
          {isUser ? <p>{msg.content}</p> : <div className="msg-content"><ReactMarkdown>{msg.content}</ReactMarkdown></div>}
        </div>
        <span className="text-xs text-gray-600 px-1">{formatTime(msg.time)}</span>
      </div>
    </div>
  );
}

export default function App() {
  const [apiKey, setApiKey] = useState(() => localStorage.getItem("abdy_openrouter_key") || "");
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [showSettings, setShowSettings] = useState(false);
  const [keyInput, setKeyInput] = useState(apiKey);
  const bottomRef = useRef(null);
  const inputRef = useRef(null);

  useEffect(() => { bottomRef.current?.scrollIntoView({ behavior: "smooth" }); }, [messages, loading]);

  const saveKey = () => {
    localStorage.setItem("abdy_openrouter_key", keyInput);
    setApiKey(keyInput);
    setShowSettings(false);
    setError("");
  };

  const sendMessage = async () => {
    if (!input.trim() || loading) return;
    if (!apiKey) { setError("⚠️ Ajoute ta clé OpenRouter dans les paramètres."); return; }
    const userMsg = { role: "user", content: input.trim(), time: new Date() };
    const newMessages = [...messages, userMsg];
    setMessages(newMessages);
    setInput("");
    setLoading(true);
    setError("");
    try {
      const res = await fetch(API_URL, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${apiKey}`,
          "HTTP-Referer": "http://localhost:3000",
          "X-Title": "Abdy AI",
        },
        body: JSON.stringify({
          model: FREE_MODEL,
          messages: [
            { role: "system", content: SYSTEM_PROMPT },
            ...newMessages.map(({ role, content }) => ({ role, content })),
          ],
        }),
      });
      if (!res.ok) { const e = await res.json(); throw new Error(e.error?.message || `Erreur ${res.status}`); }
      const data = await res.json();
      const aiText = data.choices?.[0]?.message?.content || "Désolé, pas de réponse.";
      setMessages((prev) => [...prev, { role: "assistant", content: aiText, time: new Date() }]);
    } catch (e) {
      setError(`❌ ${e.message}`);
    } finally {
      setLoading(false);
      inputRef.current?.focus();
    }
  };

  const handleKey = (e) => { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); sendMessage(); } };
  const clearChat = () => { setMessages([]); setError(""); };

  return (
    <div className="flex flex-col h-screen max-w-3xl mx-auto">
      <header className="flex items-center justify-between px-5 py-4 border-b border-white/10 bg-[#0d0d18]">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-violet-500 to-indigo-600 flex items-center justify-center text-lg shadow-lg shadow-violet-900/40">🤖</div>
          <div>
            <h1 className="font-bold text-white text-base leading-none">Abdy AI</h1>
            <p className="text-xs text-violet-400 mt-0.5">Assistant personnel de {OWNER_NAME}</p>
          </div>
        </div>
        <div className="flex items-center gap-2">
          {messages.length > 0 && <button onClick={clearChat} className="text-xs text-gray-500 hover:text-red-400 transition px-2 py-1 rounded-lg hover:bg-red-900/20">Effacer</button>}
          <button onClick={() => setShowSettings(!showSettings)} className="w-9 h-9 rounded-xl bg-white/5 hover:bg-white/10 flex items-center justify-center transition text-gray-400 hover:text-white">⚙️</button>
        </div>
      </header>

      {showSettings && (
        <div className="bg-[#12121f] border-b border-white/10 px-5 py-4 animate-fade-in">
          <p className="text-xs text-gray-400 mb-1 font-mono">Clé API OpenRouter</p>
          <p className="text-xs text-green-500 mb-2">✅ Modèle gratuit : Llama 3.3 8B</p>
          <div className="flex gap-2">
            <input type="password" value={keyInput} onChange={(e) => setKeyInput(e.target.value)} placeholder="sk-or-..." className="flex-1 bg-black/30 border border-white/10 rounded-xl px-4 py-2 text-sm text-white focus:outline-none focus:border-violet-500 font-mono" />
            <button onClick={saveKey} className="px-4 py-2 bg-violet-600 hover:bg-violet-500 text-white rounded-xl text-sm font-semibold transition">Sauvegarder</button>
          </div>
          <p className="text-xs text-gray-600 mt-2">Clé gratuite sur <a href="https://openrouter.ai/keys" target="_blank" rel="noreferrer" className="text-violet-400 hover:underline">openrouter.ai/keys</a></p>
        </div>
      )}

      <main className="flex-1 overflow-y-auto px-5 py-6">
        {messages.length === 0 && (
          <div className="flex flex-col items-center justify-center h-full gap-4 animate-fade-in text-center pb-10">
            <div className="text-5xl">👋</div>
            <h2 className="text-xl font-bold text-white">Bonjour, {OWNER_NAME.split(" ")[0]} !</h2>
            <p className="text-gray-500 text-sm max-w-sm">Ton assistant IA personnel est prêt. Pose-moi n'importe quelle question !</p>
            {!apiKey && <button onClick={() => setShowSettings(true)} className="mt-2 px-5 py-2.5 bg-violet-600 hover:bg-violet-500 rounded-xl text-sm font-semibold text-white transition">⚙️ Configurer la clé OpenRouter</button>}
            <div className="flex flex-wrap gap-2 justify-center mt-4">
              {["Quelle heure est-il à Nouakchott ?", "Explique-moi React hooks", "Aide-moi à apprendre l'arabe", "Donne-moi une recette mauritanienne"].map((q) => (
                <button key={q} onClick={() => setInput(q)} className="px-3 py-1.5 bg-white/5 hover:bg-white/10 border border-white/10 rounded-full text-xs text-gray-400 hover:text-white transition">{q}</button>
              ))}
            </div>
          </div>
        )}
        {messages.map((msg, i) => <Message key={i} msg={msg} />)}
        {loading && (
          <div className="flex gap-3 mb-4 animate-fade-in">
            <div className="w-9 h-9 rounded-xl bg-gradient-to-br from-indigo-500 to-purple-600 flex items-center justify-center text-sm">🤖</div>
            <div className="bg-[#1a1a2e] border border-white/10 rounded-2xl rounded-tl-sm"><TypingDots /></div>
          </div>
        )}
        {error && <div className="mx-auto max-w-md bg-red-900/20 border border-red-500/30 text-red-400 text-sm px-4 py-3 rounded-xl animate-fade-in">{error}</div>}
        <div ref={bottomRef} />
      </main>

      <footer className="px-5 py-4 border-t border-white/10 bg-[#0d0d18]">
        <div className="flex gap-3 items-end">
          <textarea ref={inputRef} value={input} onChange={(e) => setInput(e.target.value)} onKeyDown={handleKey} placeholder="Pose ta question, Abdy…" rows={1} className="flex-1 resize-none bg-white/5 border border-white/10 focus:border-violet-500 rounded-2xl px-4 py-3 text-sm text-white placeholder-gray-600 focus:outline-none transition max-h-36 overflow-y-auto" style={{ lineHeight: "1.6" }} />
          <button onClick={sendMessage} disabled={loading || !input.trim()} className={`flex-shrink-0 w-11 h-11 rounded-2xl flex items-center justify-center transition text-lg ${loading || !input.trim() ? "bg-white/5 text-gray-600 cursor-not-allowed" : "bg-violet-600 hover:bg-violet-500 text-white shadow-lg shadow-violet-900/40 hover:scale-105 active:scale-95"}`}>
            {loading ? "⏳" : "➤"}
          </button>
        </div>
        <p className="text-center text-xs text-gray-700 mt-2">Entrée pour envoyer • Shift+Entrée pour nouvelle ligne</p>
      </footer>
    </div>
  );
}
